import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { returnsService } from '../services/returns';
import {
  Card, StatCard, Table, StatusBadge, RiskBar,
  LoadingScreen, Alert, Button,
} from '../components/UI';
import { formatDate, formatReason, getErrorMessage } from '../utils/helpers';
import {
  PlusCircle, Package, Clock, CheckCircle, XCircle,
  ChevronRight, Inbox,
} from 'lucide-react';

export default function CustomerDashboard() {
  const { user } = useAuth();
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    returnsService.myReturns()
      .then(r => setReturns(r.data))
      .catch(e => setError(getErrorMessage(e)))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <LoadingScreen message="Loading your returns..." />;

  const counts = {
    total: returns.length,
    pending: returns.filter(r => r.status === 'pending').length,
    approved: returns.filter(r => r.status === 'approved').length,
    rejected: returns.filter(r => r.status === 'rejected').length,
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 py-8 space-y-6 animate-fade-in">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="font-display text-2xl font-bold text-slate-900">
            Welcome back, {user?.name?.split(' ')[0]} 👋
          </h1>
          <p className="text-slate-500 text-sm mt-1">Manage your return requests below</p>
        </div>
        <Link to="/customer/create-return">
          <Button icon={PlusCircle} size="md">New Return Request</Button>
        </Link>
      </div>

      {error && <Alert type="error" message={error} onClose={() => setError('')} />}

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <StatCard icon={Package} label="Total Returns" value={counts.total} color="brand" />
        <StatCard icon={Clock} label="Pending" value={counts.pending} color="blue" />
        <StatCard icon={CheckCircle} label="Approved" value={counts.approved} color="green" />
        <StatCard icon={XCircle} label="Rejected" value={counts.rejected} color="red" />
      </div>

      {/* Table */}
      <Card>
        <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between">
          <h2 className="font-display font-bold text-slate-900 text-base">Your Return Requests</h2>
          <span className="text-xs text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
            {returns.length} total
          </span>
        </div>

        {returns.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 gap-3 text-slate-400">
            <Inbox className="w-10 h-10" />
            <p className="font-medium">No return requests yet</p>
            <Link to="/customer/create-return">
              <Button variant="secondary" size="sm" icon={PlusCircle}>Create your first return</Button>
            </Link>
          </div>
        ) : (
          <Table headers={['Order ID', 'Product', 'Reason', 'Risk', 'Status', 'Submitted', '']}>
            {returns.map(r => (
              <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors group">
                <td className="px-4 py-3">
                  <span className="font-mono text-xs font-medium text-slate-700 bg-slate-100 px-2 py-0.5 rounded">
                    #{r.order_id}
                  </span>
                </td>
                <td className="px-4 py-3 text-sm font-medium text-slate-800 max-w-[160px] truncate">
                  {r.product_name}
                </td>
                <td className="px-4 py-3 text-xs text-slate-500">{formatReason(r.return_reason)}</td>
                <td className="px-4 py-3 w-36">
                  <RiskBar score={r.risk_score} />
                </td>
                <td className="px-4 py-3">
                  <StatusBadge status={r.status} />
                </td>
                <td className="px-4 py-3 text-xs text-slate-400">{formatDate(r.created_at)}</td>
                <td className="px-4 py-3">
                  <Link
                    to={`/customer/return/${r.id}`}
                    className="opacity-0 group-hover:opacity-100 transition-opacity inline-flex items-center gap-1 text-xs font-semibold text-brand-600 hover:text-brand-800"
                  >
                    View <ChevronRight className="w-3 h-3" />
                  </Link>
                </td>
              </tr>
            ))}
          </Table>
        )}
      </Card>
    </div>
  );
}
